def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    positive_bins = bins[bins > 0]
    avg_capacity = np.mean(positive_bins) if positive_bins.size > 0 else 1
    variance = np.var(positive_bins) if positive_bins.size > 0 else 0.1
    median_capacity = np.median(positive_bins) if positive_bins.size > 0 else 1
    skewness = (np.mean((positive_bins - avg_capacity)**3) / (np.std(positive_bins) ** 3)) if positive_bins.size > 1 else 0
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        if item > capacity:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1:
            score = 0.0
        elif ratio > 0.9:
            score = ((1 - ratio) ** 6) * 1.5 + 0.3
            if skewness > 0.5:
                score *= 0.9
        elif 0.65 < ratio <= 0.9:
            score = np.exp(-ratio * 18) + 0.1
            for power in range(1, 5):
                score += ((-1)**power) * (ratio ** (power+1)) / (power*1.3)
        elif 0.4 < ratio <= 0.65:
            temp = 0.0
            for k in range(1, 12):
                sign = 1 if (k % 3 == 0) else -1 if k % 2 == 0 else 1
                term = sign * (ratio ** (k + 1)) / (k * 1.15)
                temp += term
            score = abs(temp) + 0.12
        else:
            temp = 0.0
            for p in range(1, 15):
                weight = 1 / (p ** 1.5)
                sign = -1 if p % 2 == 0 else 1
                temp += sign * (ratio ** (p + 2)) * weight
            score = abs(temp) + 0.14
        neighbors_influence = 0.0
        neighbors_weights_sum = 0.0
        for offset in range(1, 10):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            local_influence = 0.0
            local_weights = 0.0
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff = abs(capacity - neighbor_capacity)
                    norm_diff = diff / max(capacity, neighbor_capacity)
                    weight = 1 / (offset ** 2.5)
                    influence = norm_diff * weight
                    if neighbor_capacity > avg_capacity + variance * 1.5:
                        influence *= 1.15
                    elif neighbor_capacity < median_capacity - variance * 1.2:
                        influence *= 0.85
                    local_influence += influence
                    local_weights += weight
            if local_weights > 0:
                neighbors_influence += local_influence / local_weights
                neighbors_weights_sum += 1 / (offset ** 1.1)
        if neighbors_weights_sum > 0:
            neighbors_influence /= neighbors_weights_sum
        cap_factor = (capacity ** 0.65) + (avg_capacity ** 0.35) + (variance ** 0.2)
        if cap_factor == 0:
            cap_factor = 1
        penalty = 0
        if capacity < item:
            penalty = ((item - capacity) ** 3.2) * 0.45
        elif capacity > item * 1.8:
            penalty = 0.055 * (np.log(capacity) if capacity > 1 else 1)
        if i % 5 == 0:
            score *= 0.85
            neighbors_influence *= 1.3
            penalty *= 1.15
        elif i % 3 == 0:
            score *= 1.05
            neighbors_influence *= 0.85
            penalty *= 1.05
        else:
            score *= 0.9
        if i > 0 and bins[i - 1] == capacity:
            penalty *= 0.7
            score *= 0.95
        priority = score + (neighbors_influence / cap_factor) + penalty
        if priority < 0:
            priority = 0
        if np.isnan(priority) or np.isinf(priority):
            priority = np.inf
        priorities[i] = priority
    finite = priorities[np.isfinite(priorities)]
    if finite.size == 0:
        return priorities
    max_finite = np.max(finite)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 7
    return priorities
